// --- Helpers ---
function extractEmailAddress(fromObj) {
  // Check for the specific structure in your JSON: from.value[0].address
  if (fromObj && fromObj.value && fromObj.value[0] && fromObj.value[0].address) {
    return fromObj.value[0].address.toLowerCase();
  }
  // Fallback for string-based "From" headers
  if (typeof fromObj === 'string') {
    const match = fromObj.match(/<([^>]+)>/);
    return match ? match[1].trim().toLowerCase() : fromObj.trim().toLowerCase();
  }
  return '';
}

function b64urlDecode(str) {
  if (!str) return '';
  str = str.replace(/-/g, '+').replace(/_/g, '/');
  const pad = str.length % 4;
  if (pad) str += '='.repeat(4 - pad);
  try {
    return Buffer.from(str, 'base64').toString('utf8');
  } catch (e) {
    return str; // Return as is if not base64
  }
}

function findTextPlain(payload) {
  if (!payload || !payload.parts) return '';
  const parts = payload.parts || [];
  for (const p of parts) {
    if (p.mimeType === 'text/plain' && p.body && p.body.data) {
      return b64urlDecode(p.body.data);
    }
    if (p.parts) {
      const nested = findTextPlain(p);
      if (nested) return nested;
    }
  }
  return '';
}

function stripQuoted(text) {
  if (!text) return '';
  const patterns = [
    /\nOn .*wrote:\n[\s\S]*$/i,
    /\nFrom: .*[\s\S]*$/i,
    /\n-----Original Message-----[\s\S]*$/i
  ];
  let t = text.trim();
  for (const re of patterns) t = t.replace(re, '').trim();
  return t;
}

// --- Main ---
// Check if we are dealing with the nested "payload" structure or the flat JSON provided
const payload = $json.payload || null;

// Subject
const subject = $json.subject || (payload ? (payload.headers.find(h => h.name === 'Subject') || {}).value : '');

// From / Customer Email
const fromRaw = $json.from ? $json.from.text : ''; 
const customerEmail = extractEmailAddress($json.from);

// Body Text
// Priority: 1. Direct "text" key (your JSON) 2. "textPlain" 3. Crawl payload parts
let bodyText = $json.text || $json.textPlain || findTextPlain(payload) || $json.snippet || '';
bodyText = stripQuoted(bodyText);

const snippet = (bodyText || '').slice(0, 2000);

return [{
  json: {
    threadId: $json.threadId || '',
    messageId: $json.messageId || $json.id || '',
    subject: subject,
    fromRaw: fromRaw,
    customerEmail: customerEmail,
    dateRaw: $json.date || '',
    inboundBody: bodyText,
    inboundSnippet: snippet
  }
}];

